    26|export function getRealtimeConfig(): RealtimeAdapterConfig {
    27|  const redisUrl = process.env.REDIS_URL ?? null;
    28|  const enabled = redisUrl !== null && process.env.IVX_REDIS_ADAPTER_ENABLED === 'true';
    29|  const instanceId = `${process.env.HOST ?? 'localhost'}-${process.env.PORT ?? '3000'}-${Date.now()}`;
    30|  return {
    31|    enabled,
    32|    redisUrl,
    33|    instanceId,
    34|    maxPayloadBytes: 1_000_000,
    35|    pingIntervalMs: 10_000,
    36|    pingTimeoutMs: 30_000,
