    40|/**
    41| * Attach Redis adapter to Socket.IO server if Redis is available.
    42| * Returns true if adapter was attached, false if running in-memory.
    43| */
    44|export async function attachRedisAdapter(io: SocketIOServer): Promise<boolean> {
    45|  const config = getRealtimeConfig();
    46|  if (!config.enabled || !config.redisUrl) {
    47|    console.log('[IVX Realtime] Using in-memory adapter (single instance)', { marker: ADAPTER_MARKER });
    48|    return false;
    49|  }
    50|
    51|  try {
    52|    const { createAdapter } = await import('@socket.io/redis-adapter');
    53|    const { createClient } = await import('redis');
    54|    const pubClient = createClient({ url: config.redisUrl });
    55|    const subClient = pubClient.duplicate();
    56|    await Promise.all([pubClient.connect(), subClient.connect()]);
    57|    io.adapter(createAdapter(pubClient, subClient));
    58|    console.log('[IVX Realtime] Redis adapter attached', {
    59|      marker: ADAPTER_MARKER,
    60|      instanceId: config.instanceId,
    61|    });
    62|    return true;
    63|  } catch (error) {
    64|    console.error('[IVX Realtime] Redis adapter failed, falling back to in-memory', {
    65|      error: error instanceof Error ? error.message : String(error),
    66|      marker: ADAPTER_MARKER,
    67|    });
    68|    return false;
    69|  }
